import React, { useState, useRef, useEffect } from "react";

function Attendance() {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const [step, setStep] = useState("idle"); // idle | scanning | processing | done | error
  const [message, setMessage] = useState("");
  const [attendanceLog, setAttendanceLog] = useState([]);
  const [stream, setStream] = useState(null);
  const [progress, setProgress] = useState(0);

  const student = JSON.parse(localStorage.getItem("student")) || { name: "Student", id: "N/A" };

  // Load existing attendance from backend on mount
  useEffect(() => {
    fetchAttendance();
  }, []);

  const fetchAttendance = async () => {
    try {
      const res = await fetch("http://localhost:5000/attendance/" + student.id);
      const data = await res.json();
      setAttendanceLog(data);
    } catch (err) {
      console.log("Could not fetch attendance");
    }
  };

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: "user", width: 400, height: 300 },
      });
      videoRef.current.srcObject = mediaStream;
      setStream(mediaStream);
      setStep("scanning");
      setMessage("👁️ Please look directly at the camera...");
    } catch (err) {
      setStep("error");
      setMessage("❌ Camera access denied. Please allow camera permission.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach((track) => track.stop());
      setStream(null);
    }
  };

  const scanIris = () => {
    setStep("processing");
    setMessage("🔍 Scanning iris pattern...");
    setProgress(0);

    // Simulate iris scan progress
    let prog = 0;
    const interval = setInterval(() => {
      prog += 10;
      setProgress(prog);
      if (prog === 30) setMessage("🔍 Detecting eye pattern...");
      if (prog === 60) setMessage("🔍 Matching iris data...");
      if (prog === 90) setMessage("✅ Iris matched! Marking attendance...");
      if (prog >= 100) {
        clearInterval(interval);
        markAttendance();
      }
    }, 300);
  };

  const markAttendance = async () => {
    stopCamera();

    const now = new Date();
    const record = {
      studentId: student.id,
      studentName: student.name,
      date: now.toLocaleDateString("en-IN"),
      time: now.toLocaleTimeString("en-IN"),
      status: "Present",
      method: "Iris Scan",
    };

    try {
      await fetch("http://localhost:5000/attendance", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(record),
      });
      setStep("done");
      setMessage("✅ Attendance marked successfully via Iris Scan!");
      fetchAttendance();
    } catch (err) {
      setStep("done");
      setMessage("✅ Attendance marked! (offline mode)");
      setAttendanceLog((prev) => [record, ...prev]);
    }
  };

  const reset = () => {
    stopCamera();
    setStep("idle");
    setMessage("");
    setProgress(0);
  };

  // Check if already marked today
  const today = new Date().toLocaleDateString("en-IN");
  const alreadyMarked = attendanceLog.some(
    (r) => r.date === today && r.studentId === student.id
  );

  return (
    <div className="content">
      <h3>👁️ Iris Scan Attendance</h3>
      <p style={{ color: "#555", marginTop: "5px" }}>
        Student: <strong>{student.name}</strong> | ID: <strong>{student.id}</strong>
      </p>

      {/* Already marked today */}
      {alreadyMarked && step === "idle" && (
        <div style={styles.successBox}>
          ✅ Attendance already marked for today ({today})
        </div>
      )}

      {/* Idle State */}
      {step === "idle" && !alreadyMarked && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={styles.irisIcon}>👁️</div>
          <p style={{ color: "#555", marginBottom: "20px" }}>
            Click below to start iris scan and mark your attendance
          </p>
          <button style={styles.scanBtn} onClick={startCamera}>
            Start Iris Scan
          </button>
        </div>
      )}

      {/* Camera View */}
      {(step === "scanning" || step === "processing") && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          {/* Camera Feed */}
          <div style={styles.cameraWrapper}>
            <video
              ref={videoRef}
              autoPlay
              playsInline
              muted
              style={styles.video}
            />
            {/* Iris overlay */}
            <div style={styles.irisOverlay}>
              <div style={{
                ...styles.irisRing,
                borderColor: step === "processing" ? "#00ff88" : "#007bff",
                animation: step === "processing" ? "pulse 0.5s infinite" : "pulse 1.5s infinite",
              }} />
              <div style={{
                ...styles.irisRingInner,
                borderColor: step === "processing" ? "#00ff88" : "#007bff",
              }} />
            </div>
          </div>

          <canvas ref={canvasRef} style={{ display: "none" }} />

          {/* Progress bar */}
          {step === "processing" && (
            <div style={styles.progressBar}>
              <div style={{ ...styles.progressFill, width: progress + "%" }} />
            </div>
          )}

          <p style={{ marginTop: "10px", color: step === "processing" ? "#007bff" : "#333", fontWeight: "bold" }}>
            {message}
          </p>

          {step === "scanning" && (
            <div style={{ marginTop: "15px" }}>
              <button style={styles.scanBtn} onClick={scanIris}>
                📸 Capture & Scan Iris
              </button>
              <button style={styles.cancelBtn} onClick={reset}>
                Cancel
              </button>
            </div>
          )}
        </div>
      )}

      {/* Done State */}
      {step === "done" && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={styles.successBox}>{message}</div>
          <button style={styles.scanBtn} onClick={reset}>
            Scan Again
          </button>
        </div>
      )}

      {/* Error State */}
      {step === "error" && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={styles.errorBox}>{message}</div>
          <button style={styles.scanBtn} onClick={reset}>
            Try Again
          </button>
        </div>
      )}

      {/* Attendance Log */}
      <div style={{ marginTop: "30px" }}>
        <h4>📋 Your Attendance Record</h4>
        {attendanceLog.length === 0 ? (
          <p style={{ color: "#888", marginTop: "10px" }}>No attendance records yet.</p>
        ) : (
          <table className="timetable" style={{ marginTop: "10px" }}>
            <thead>
              <tr>
                <th>Date</th>
                <th>Time</th>
                <th>Status</th>
                <th>Method</th>
              </tr>
            </thead>
            <tbody>
              {attendanceLog.map((r, i) => (
                <tr key={i}>
                  <td>{r.date}</td>
                  <td>{r.time}</td>
                  <td style={{ color: "green", fontWeight: "bold" }}>{r.status}</td>
                  <td>{r.method}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* CSS animation */}
      <style>{`
        @keyframes pulse {
          0% { transform: translate(-50%, -50%) scale(1); opacity: 1; }
          50% { transform: translate(-50%, -50%) scale(1.08); opacity: 0.7; }
          100% { transform: translate(-50%, -50%) scale(1); opacity: 1; }
        }
      `}</style>
    </div>
  );
}

